#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long a_first = 500 - 2 * X;
        if (a_first < 0) a_first = 0;
        long long b_after_a = 1000 - 4 * (X + Y);
        if (b_after_a < 0) b_after_a = 0;
        long long total1 = a_first + b_after_a;

        long long b_first = 1000 - 4 * Y;
        if (b_first < 0) b_first = 0;
        long long a_after_b = 500 - 2 * (X + Y);
        if (a_after_b < 0) a_after_b = 0;
        long long total2 = b_first + a_after_b;

        long long ans = total1 > total2 ? total1 : total2;
        printf("%lld\n", ans);
    }
    return 0;
}

