code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long X = Long.parseLong(st.nextToken());
            long Y = Long.parseLong(st.nextToken());
            long aFirst = Math.max(0, 500 - 2 * X);
            long bAfterA = Math.max(0, 1000 - 4 * (X + Y));
            long total1 = aFirst + bAfterA;
            long bFirst = Math.max(0, 1000 - 4 * Y);
            long aAfterB = Math.max(0, 500 - 2 * (X + Y));
            long total2 = bFirst + aAfterB;
            sb.append(Math.max(total1, total2)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

